export const CALENDAR_CORE_SOURCE = "// Calendar behavior core (proposal 0029, Tier 1).\n//\n// Pure TypeScript: no DOM, no JSX, no framework, no ambient clock (`today` is an\n// INPUT, never read from Date.now) and no i18n (month/weekday *labels* are the\n// view's Intl concern - this core only orders and classifies cells). It is the\n// single source of truth for DatePicker logic, imported verbatim by every web\n// framework view so a React MFE and a Vue MFE compute an identical calendar.\n//\n// Internal canonical form is `{ year, month, day }` with **month 1-12** (calendar-\n// honest, matching Temporal.PlainDate / @internationalized/date CalendarDate, and\n// avoiding the JS Date 0-index footgun leaking into this layer). The thin view\n// converts to/from the project's chosen representation (isoDate | nativeDate | ...)\n// at the boundary; representation never enters this file.\n\n/** A timezone-less calendar date. `month` is 1-12, `day` is 1-31. */\nexport interface YMD {\n  year: number\n  month: number\n  day: number\n}\n\n/** 0 = Sunday ... 6 = Saturday (matches `Date.prototype.getUTCDay`). */\nexport type Weekday = 0 | 1 | 2 | 3 | 4 | 5 | 6\n\nexport type SingleSelection = YMD | null\n/** `end` is null while the user has picked only the first endpoint. */\nexport type RangeSelection = { start: YMD; end: YMD | null } | null\n\nexport interface CalendarInput {\n  /** Month currently shown in the grid. `month` is 1-12. */\n  displayedMonth: { year: number; month: number }\n  /** First column of the grid. Defaults to Sunday (0). */\n  weekStartsOn?: Weekday\n  mode?: 'single' | 'range'\n  /** `SingleSelection` in single mode, `RangeSelection` in range mode. */\n  selection?: SingleSelection | RangeSelection\n  /** Inclusive lower bound; dates before it are `disabled`. */\n  min?: YMD\n  /** Inclusive upper bound; dates after it are `disabled`. */\n  max?: YMD\n  /** Weekday indices (0-6) that are always `disabled` (e.g. weekends). */\n  disabledWeekdays?: Weekday[]\n  /** Range mode: the cell under the cursor, for previewing the span. */\n  hoverPreview?: YMD | null\n  /** The reference \"today\", injected so the core stays pure/deterministic. */\n  today?: YMD | null\n  /** Escape hatch: arbitrary per-date disabling (proposal 0029 §2). */\n  isDateDisabled?: (date: YMD) => boolean\n  /** Escape hatch: arbitrary per-date highlighting. */\n  isDateHighlighted?: (date: YMD) => boolean\n}\n\nexport interface CalendarCellState {\n  today: boolean\n  disabled: boolean\n  /** Cell belongs to a previous/next month, shown to complete the week. */\n  outsideMonth: boolean\n  selected: boolean\n  rangeStart: boolean\n  rangeEnd: boolean\n  /** Strictly between the range endpoints (endpoints excluded). */\n  inRange: boolean\n  highlighted: boolean\n}\n\nexport interface CalendarCell {\n  date: YMD\n  states: CalendarCellState\n}\n\nexport interface CalendarModel {\n  displayedMonth: { year: number; month: number }\n  /** The 7 weekday indices in display order, e.g. `[1,2,3,4,5,6,0]` for Monday-start. */\n  weekdayOrder: Weekday[]\n  /** Complete weeks (7 cells each) covering the displayed month. */\n  weeks: CalendarCell[][]\n  /** Displayed month shifted by -1, for the \"prev\" control. */\n  prevMonth: { year: number; month: number }\n  /** Displayed month shifted by +1, for the \"next\" control. */\n  nextMonth: { year: number; month: number }\n}\n\n// --- pure date arithmetic (UTC-based, deterministic given inputs) --------------\n\n/** Number of days in a 1-12 month. */\nexport function daysInMonth(year: number, month: number): number {\n  // Day 0 of the *next* month rolls back to the last day of `month`.\n  return new Date(Date.UTC(year, month, 0)).getUTCDate()\n}\n\n/** Weekday (0 = Sunday) of a calendar date. */\nexport function dayOfWeek(d: YMD): Weekday {\n  return new Date(Date.UTC(d.year, d.month - 1, d.day)).getUTCDay() as Weekday\n}\n\n/** Add (or subtract) whole days, normalizing across month/year boundaries. */\nexport function addDays(d: YMD, n: number): YMD {\n  const dt = new Date(Date.UTC(d.year, d.month - 1, d.day + n))\n  return { year: dt.getUTCFullYear(), month: dt.getUTCMonth() + 1, day: dt.getUTCDate() }\n}\n\n/** Shift a year/month by `delta` months (1-12 output month). */\nexport function addMonths(m: { year: number; month: number }, delta: number): {\n  year: number\n  month: number\n} {\n  const zeroBased = m.year * 12 + (m.month - 1) + delta\n  return { year: Math.floor(zeroBased / 12), month: ((zeroBased % 12) + 12) % 12 + 1 }\n}\n\n/** Chronological comparison: negative if `a < b`, 0 if equal, positive if `a > b`. */\nexport function compareYMD(a: YMD, b: YMD): number {\n  return a.year - b.year || a.month - b.month || a.day - b.day\n}\n\nconst sameDay = (a: YMD | null | undefined, b: YMD | null | undefined): boolean =>\n  !!a && !!b && compareYMD(a, b) === 0\n\n// --- model construction --------------------------------------------------------\n\ntype EffectiveRange = { a: YMD; b: YMD | null } | null\n\n/** Normalize a range selection (+ optional hover preview) into ordered endpoints. */\nfunction effectiveRange(sel: RangeSelection, hover: YMD | null | undefined): EffectiveRange {\n  if (!sel) return null\n  const end = sel.end ?? hover ?? null\n  if (!end) return { a: sel.start, b: null }\n  return compareYMD(sel.start, end) <= 0 ? { a: sel.start, b: end } : { a: end, b: sel.start }\n}\n\nexport function buildCalendar(input: CalendarInput): CalendarModel {\n  const weekStartsOn = input.weekStartsOn ?? 0\n  const mode = input.mode ?? 'single'\n  const { year, month } = input.displayedMonth\n  const disabledWeekdays = new Set(input.disabledWeekdays ?? [])\n\n  const single = mode === 'single' ? (input.selection as SingleSelection) ?? null : null\n  const range = mode === 'range' ? effectiveRange((input.selection as RangeSelection) ?? null, input.hoverPreview) : null\n\n  // Leading blanks: how many days of the previous month fill the first row.\n  const firstDow = dayOfWeek({ year, month, day: 1 })\n  const lead = (firstDow - weekStartsOn + 7) % 7\n  const gridStart = addDays({ year, month, day: 1 }, -lead)\n\n  const total = daysInMonth(year, month)\n  const weeksCount = Math.ceil((lead + total) / 7)\n\n  const weeks: CalendarCell[][] = []\n  for (let w = 0; w < weeksCount; w++) {\n    const row: CalendarCell[] = []\n    for (let d = 0; d < 7; d++) {\n      const date = addDays(gridStart, w * 7 + d)\n      row.push({ date, states: classify(date) })\n    }\n    weeks.push(row)\n  }\n\n  return {\n    displayedMonth: { year, month },\n    weekdayOrder: Array.from({ length: 7 }, (_, i) => ((weekStartsOn + i) % 7) as Weekday),\n    weeks,\n    prevMonth: addMonths({ year, month }, -1),\n    nextMonth: addMonths({ year, month }, 1),\n  }\n\n  function classify(date: YMD): CalendarCellState {\n    const disabled =\n      (input.min != null && compareYMD(date, input.min) < 0) ||\n      (input.max != null && compareYMD(date, input.max) > 0) ||\n      disabledWeekdays.has(dayOfWeek(date)) ||\n      (input.isDateDisabled?.(date) ?? false)\n\n    const rangeStart = !!range && (range.b != null ? sameDay(date, range.a) : sameDay(date, range.a))\n    const rangeEnd = !!range && range.b != null && sameDay(date, range.b)\n    const inRange =\n      !!range &&\n      range.b != null &&\n      compareYMD(date, range.a) > 0 &&\n      compareYMD(date, range.b) < 0\n\n    const selected = mode === 'range' ? rangeStart || rangeEnd : sameDay(date, single)\n\n    return {\n      today: sameDay(date, input.today),\n      disabled,\n      outsideMonth: date.month !== month || date.year !== year,\n      selected,\n      rangeStart,\n      rangeEnd,\n      inRange,\n      highlighted: input.isDateHighlighted?.(date) ?? false,\n    }\n  }\n}\n"

export const TIME_CORE_SOURCE = "// Time behavior core (proposal 0029, Tier 1 - sibling of calendar.ts).\n//\n// Pure TypeScript: no DOM, no JSX, no framework, no i18n (labels are the view's\n// Intl concern). Single source of truth for TimePicker slot logic, vendored beside\n// the component so every framework target computes an identical time list. Canonical\n// form is `{ hour, minute }` (24h, hour 0-23, minute 0-59); the thin view converts\n// to/from the project's representation and formats labels via Intl.\n\n/** A wall-clock time of day. `hour` is 0-23, `minute` is 0-59. */\nexport interface HM {\n  hour: number\n  minute: number\n}\n\nexport interface TimeInput {\n  /** Minutes between adjacent slots (e.g. 15, 30, 60). Clamped to >= 1. */\n  step: number\n  /** Inclusive earliest selectable time; earlier slots are `disabled`. */\n  min?: HM\n  /** Inclusive latest selectable time; later slots are `disabled`. */\n  max?: HM\n  selection?: HM | null\n  /** Escape hatch: arbitrary per-slot disabling. */\n  isTimeDisabled?: (time: HM) => boolean\n}\n\nexport interface TimeCellState {\n  selected: boolean\n  disabled: boolean\n}\n\nexport interface TimeCell {\n  value: HM\n  states: TimeCellState\n}\n\n// --- pure helpers --------------------------------------------------------------\n\n/** Minutes since midnight for an HM (0-1439). */\nexport function toMinutes(t: HM): number {\n  return t.hour * 60 + t.minute\n}\n\n/** HM from minutes since midnight (wraps into 0-1439). */\nexport function fromMinutes(n: number): HM {\n  const m = ((n % 1440) + 1440) % 1440\n  return { hour: Math.floor(m / 60), minute: m % 60 }\n}\n\n/** Chronological comparison within a day: negative if `a < b`, 0 if equal. */\nexport function compareHM(a: HM, b: HM): number {\n  return toMinutes(a) - toMinutes(b)\n}\n\n// --- slot list construction ----------------------------------------------------\n\nexport function buildTimeList(input: TimeInput): TimeCell[] {\n  const step = Math.max(1, Math.floor(input.step))\n  const cells: TimeCell[] = []\n  for (let m = 0; m < 1440; m += step) {\n    const value = fromMinutes(m)\n    const disabled =\n      (input.min != null && compareHM(value, input.min) < 0) ||\n      (input.max != null && compareHM(value, input.max) > 0) ||\n      (input.isTimeDisabled?.(value) ?? false)\n    const selected = input.selection != null && compareHM(value, input.selection) === 0\n    cells.push({ value, states: { selected, disabled } })\n  }\n  return cells\n}\n"

export const COLOR_CORE_SOURCE = "// Color behavior core (proposal 0029, Tier 1 - sibling of calendar.ts / timepicker.ts).\n//\n// Pure TypeScript: no DOM, no JSX, no framework, no i18n. Single source of truth for\n// ColorPicker math (HSV <-> RGB <-> hex <-> HSL) + the saturation/value area and hue\n// slider geometry, vendored beside the component so every framework target computes an\n// identical picker. Canonical working form is HSV (hue 0-360, sat/val 0-1) - the\n// natural space for a 2D area + hue slider. The thin view converts to/from the\n// project's chosen representation (hex | rgb | hsl) at the boundary.\n\n/** Hue 0-360, saturation 0-1, value 0-1. */\nexport interface HSV {\n  h: number\n  s: number\n  v: number\n}\n/** Red/green/blue, each 0-255 (integers). */\nexport interface RGB {\n  r: number\n  g: number\n  b: number\n}\n/** Hue 0-360, saturation 0-1, lightness 0-1. */\nexport interface HSL {\n  h: number\n  s: number\n  l: number\n}\n\nconst clampN = (n: number, lo: number, hi: number): number => (n < lo ? lo : n > hi ? hi : n)\nconst round = (n: number): number => Math.round(n)\n\n/** Clamp an HSV into range (hue wraps 0-360, s/v clamp 0-1). */\nexport function clampHsv(c: HSV): HSV {\n  return { h: ((c.h % 360) + 360) % 360, s: clampN(c.s, 0, 1), v: clampN(c.v, 0, 1) }\n}\n\n// hp = hue/60 sector; (r1,g1,b1) before adding the achromatic offset. Shared by HSV/HSL.\nfunction sector(hp: number, chroma: number, x: number): [number, number, number] {\n  if (hp < 1) return [chroma, x, 0]\n  if (hp < 2) return [x, chroma, 0]\n  if (hp < 3) return [0, chroma, x]\n  if (hp < 4) return [0, x, chroma]\n  if (hp < 5) return [x, 0, chroma]\n  return [chroma, 0, x]\n}\n\nexport function hsvToRgb(c: HSV): RGB {\n  const { h, s, v } = clampHsv(c)\n  const chroma = v * s\n  const hp = h / 60\n  const x = chroma * (1 - Math.abs((hp % 2) - 1))\n  const [r1, g1, b1] = sector(hp, chroma, x)\n  const m = v - chroma\n  return { r: round((r1 + m) * 255), g: round((g1 + m) * 255), b: round((b1 + m) * 255) }\n}\n\nexport function rgbToHsv(c: RGB): HSV {\n  const r = clampN(c.r, 0, 255) / 255\n  const g = clampN(c.g, 0, 255) / 255\n  const b = clampN(c.b, 0, 255) / 255\n  const max = Math.max(r, g, b)\n  const min = Math.min(r, g, b)\n  const d = max - min\n  let h = 0\n  if (d !== 0) {\n    if (max === r) h = ((g - b) / d) % 6\n    else if (max === g) h = (b - r) / d + 2\n    else h = (r - g) / d + 4\n    h *= 60\n    if (h < 0) h += 360\n  }\n  return { h, s: max === 0 ? 0 : d / max, v: max }\n}\n\nconst hex2 = (n: number): string => clampN(round(n), 0, 255).toString(16).padStart(2, '0')\n\nexport function rgbToHex(c: RGB): string {\n  return `#${hex2(c.r)}${hex2(c.g)}${hex2(c.b)}`\n}\n\n/** Parse #rgb / #rrggbb (with or without leading #). Returns null if malformed. */\nexport function hexToRgb(hex: string): RGB | null {\n  let h = hex.trim().replace(/^#/, '')\n  if (h.length === 3) h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2]\n  if (h.length !== 6 || /[^0-9a-fA-F]/.test(h)) return null\n  return { r: parseInt(h.slice(0, 2), 16), g: parseInt(h.slice(2, 4), 16), b: parseInt(h.slice(4, 6), 16) }\n}\n\nexport function hsvToHex(c: HSV): string {\n  return rgbToHex(hsvToRgb(c))\n}\n\nexport function hexToHsv(hex: string): HSV | null {\n  const rgb = hexToRgb(hex)\n  return rgb ? rgbToHsv(rgb) : null\n}\n\nexport function rgbToHsl(c: RGB): HSL {\n  const { h } = rgbToHsv(c)\n  const r = clampN(c.r, 0, 255) / 255\n  const g = clampN(c.g, 0, 255) / 255\n  const b = clampN(c.b, 0, 255) / 255\n  const max = Math.max(r, g, b)\n  const min = Math.min(r, g, b)\n  const l = (max + min) / 2\n  const d = max - min\n  const s = d === 0 ? 0 : d / (1 - Math.abs(2 * l - 1))\n  return { h, s, l }\n}\n\nexport function hslToRgb(c: HSL): RGB {\n  const h = ((c.h % 360) + 360) % 360\n  const s = clampN(c.s, 0, 1)\n  const l = clampN(c.l, 0, 1)\n  const chroma = (1 - Math.abs(2 * l - 1)) * s\n  const hp = h / 60\n  const x = chroma * (1 - Math.abs((hp % 2) - 1))\n  const [r1, g1, b1] = sector(hp, chroma, x)\n  const m = l - chroma / 2\n  return { r: round((r1 + m) * 255), g: round((g1 + m) * 255), b: round((b1 + m) * 255) }\n}\n\n// --- picker geometry -----------------------------------------------------------\n\nexport interface ColorModel {\n  hsv: HSV\n  rgb: RGB\n  hex: string\n  /** Saturation-value area thumb, normalized 0-1 (origin top-left: x=saturation, y=1-value). */\n  area: { x: number; y: number }\n  /** Hue slider thumb position, normalized 0-1 along the track. */\n  hueX: number\n  /** The pure hue as a CSS color, for painting the area's base (e.g. `hsl(h, 100%, 50%)`). */\n  hueCss: string\n}\n\n/** Derive display values + thumb positions from an HSV color. */\nexport function buildColor(input: HSV): ColorModel {\n  const hsv = clampHsv(input)\n  const rgb = hsvToRgb(hsv)\n  return {\n    hsv,\n    rgb,\n    hex: rgbToHex(rgb),\n    area: { x: hsv.s, y: 1 - hsv.v },\n    hueX: hsv.h / 360,\n    hueCss: `hsl(${round(hsv.h)}, 100%, 50%)`,\n  }\n}\n\n/** New HSV from a pointer position on the saturation-value area (x,y normalized 0-1). */\nexport function hsvFromArea(hue: number, x: number, y: number): HSV {\n  return { h: hue, s: clampN(x, 0, 1), v: 1 - clampN(y, 0, 1) }\n}\n\n/** New hue (0-360) from a pointer position along the hue track (x normalized 0-1). */\nexport function hueFromTrack(x: number): number {\n  return clampN(x, 0, 1) * 360\n}\n"
